/* Compare a class name (NUL-terminated) against a target type name (ptr,len),
 * both truncated at the first '$' so a generic specialization like
 * "Vector$f64" matches the base name "Vector". Backs the string form of
 * is_a? used by synthesized operator-overload dispatchers. */
static int w_typename_base_eq(const char *cls_name, const char *tn, size_t tn_len) {
    size_t i = 0;
    while (1) {
        char ca = cls_name[i];
        char cb = (i < tn_len) ? tn[i] : '\0';
        if (ca == '$') ca = '\0';
        if (cb == '$') cb = '\0';
        if (ca != cb) return 0;
        if (ca == '\0') return 1;
        i++;
    }
}

static int w_type_name_eq_lit(const char *tn, size_t tn_len, const char *lit) {
    size_t i = 0;
    while (lit[i]) {
        if (i >= tn_len || tn[i] != lit[i]) return 0;
        i++;
    }
    return i == tn_len;
}

static int w_primitive_is_a_type_name(WValue recv, const char *tn, size_t tn_len) {
    if (w_is_ipv4(recv))
        return w_type_name_eq_lit(tn, tn_len, "IPv4");
    if (w_is_ipv6(recv))
        return w_type_name_eq_lit(tn, tn_len, "IPv6");
    if (w_is_mac(recv))
        return w_type_name_eq_lit(tn, tn_len, "MAC");
    if (w_is_int(recv)) {
        return w_type_name_eq_lit(tn, tn_len, "Integer") ||
               w_type_name_eq_lit(tn, tn_len, "Int") ||
               w_type_name_eq_lit(tn, tn_len, "Real") ||
               w_type_name_eq_lit(tn, tn_len, "Number");
    }
    if (w_is_bigint(recv)) {
        return w_type_name_eq_lit(tn, tn_len, "BigInt") ||
               w_type_name_eq_lit(tn, tn_len, "Integer") ||
               w_type_name_eq_lit(tn, tn_len, "Int") ||
               w_type_name_eq_lit(tn, tn_len, "Real") ||
               w_type_name_eq_lit(tn, tn_len, "Number");
    }
    if (w_is_double(recv)) {
        return w_type_name_eq_lit(tn, tn_len, "Float") ||
               w_type_name_eq_lit(tn, tn_len, "Real") ||
               w_type_name_eq_lit(tn, tn_len, "Number");
    }
    if (is_decimal_any(recv)) {
        return w_type_name_eq_lit(tn, tn_len, "Decimal") ||
               w_type_name_eq_lit(tn, tn_len, "Real") ||
               w_type_name_eq_lit(tn, tn_len, "Number");
    }
    return 0;
}

/* Runtime ancestry primitive shared by public is_a? and compiler-generated
 * typed-overload gates. Keeping the gate callable directly avoids hashing and
 * looking up `is_a?` for every overloaded operator invocation. */
WValue w_value_is_a(WValue recv, WValue target) {
    /* Class-object target: walk instance ancestry by class_id. */
    if (w_is_class(target)) {
        WClass *tc = (WClass *)w_as_ptr(target);
        if (w_is_instance(recv)) {
            WClass *k = g_class_table[((WObject *)w_as_ptr(recv))->class_id];
            while (k) {
                if (k->class_id == tc->class_id) return w_bool(1);
                k = k->superclass;
            }
            return w_bool(0);
        }
        if (w_is_class(recv)) return w_bool(0);
        const char *pn =
            w_is_int(recv) ? "Integer" :
            w_is_double(recv) ? "Float" :
            w_is_string(recv) ? "String" :
            w_is_symbol(recv) ? "Symbol" :
            (w_is_array(recv) || w_is_body(recv)) ? "Array" :
            w_is_bool(recv) ? "Boolean" : NULL;
        return w_bool((pn && strcmp(pn, tc->name) == 0) ||
                      w_primitive_is_a_type_name(recv, tc->name, strlen(tc->name)));
    }

    /* String target: compare generic specializations by base name. Resolve
     * instances first — the hot overload-gate path — before probing primitive
     * tags or constructing a primitive type name. */
    if (w_is_stringy(target)) {
        char sbuf[6];
        const char *tn;
        size_t tn_len;
        w_str_data(target, sbuf, &tn, &tn_len);
        if (w_is_instance(recv)) {
            WClass *k = g_class_table[((WObject *)w_as_ptr(recv))->class_id];
            while (k) {
                if (w_typename_base_eq(k->name, tn, tn_len)) return w_bool(1);
                k = k->superclass;
            }
            return w_bool(0);
        }
        if (w_is_class(recv))
            return w_bool(w_typename_base_eq(((WClass *)w_as_ptr(recv))->name, tn, tn_len));
        const char *pn =
            w_is_int(recv) ? "Integer" :
            w_is_double(recv) ? "Float" :
            w_is_string(recv) ? "String" :
            w_is_symbol(recv) ? "Symbol" :
            (w_is_array(recv) || w_is_body(recv)) ? "Array" :
            w_is_bool(recv) ? "Boolean" : NULL;
        return w_bool((pn && w_typename_base_eq(pn, tn, tn_len)) ||
                      w_primitive_is_a_type_name(recv, tn, tn_len));
    }
    return w_bool(0);
}

