static WValue w_method_dispatch(WValue recv, WValue name, WArray *args, WValue args_arr);

/* Phase 4f follow-up forward decl: the body lives with the typed-array
 * helpers. Native storage/leaf methods (each, any?/all?/none?, compact, dup,
 * uniq, count/index) use it so non-w64 arrays decode per ebits. Enumerable
 * combinators consume those decoded values through Array#each. */
static WValue array_slot_load_decoded(WArray *a, int64_t i);
static inline int array_is_float(const WArray *a);
static inline int array_is_signed_int(const WArray *a);
static inline int array_is_byte_int_array(const WArray *a);

/* Comparison function for qsort — supports ints, floats, strings */
static int w_value_compare(const void *ap, const void *bp) {
    WValue a = *(const WValue *)ap;
    WValue b = *(const WValue *)bp;
    /* Both ints */
    if (w_is_int(a) && w_is_int(b)) {
        int64_t ia = w_as_int(a), ib = w_as_int(b);
        return (ia > ib) - (ia < ib);
    }
    /* Both doubles */
    if (w_is_double(a) && w_is_double(b)) {
        double da = w_as_double(a), db = w_as_double(b);
        return (da > db) - (da < db);
    }
    /* Int vs double or double vs int */
    if ((w_is_int(a) || w_is_double(a)) && (w_is_int(b) || w_is_double(b))) {
        double da = w_is_int(a) ? (double)w_as_int(a) : w_as_double(a);
        double db = w_is_int(b) ? (double)w_as_int(b) : w_as_double(b);
        return (da > db) - (da < db);
    }
    /* Both strings */
    if (w_is_string(a) && w_is_string(b)) {
        return strcmp(as_str(a), as_str(b));
    }
    /* Fallback: compare raw bits for stable sort */
    return (a > b) - (a < b);
}

WValue w_method_call(WValue recv, WValue method_name, WValue args_arr) {
    WArray *args = as_array(args_arr);
    WValue result = w_method_dispatch(recv, method_name, args, args_arr);
    /* Recycle the args array — it was allocated by codegen just for this call */
    w_array_recycle(args_arr);
    return result;
}

/* Fast method dispatch: args passed on C stack, no heap allocation. */
WValue w_method_call_fast(WValue recv, WValue name, WValue *args_ptr, int argc) {
    WArray stack_args;
    stack_args.slots = args_ptr;
    stack_args.start = 0;
    stack_args.size = argc;
    stack_args.cap = argc;
    return w_method_dispatch(recv, name, &stack_args, W_NIL);
}

/* ---- Monomorphic inline cache ---- */

static inline uint64_t w_dispatch_key(WValue v) {
    if (__builtin_expect(v < 0x10, 0)) return 0;
    uint64_t hi = v >> 48;
    if (hi == 0) {
        uint64_t subtag = v & 0xF;
        if (subtag == W_SUBTAG_INSTANCE) {
            WObject *obj = (WObject *)w_as_ptr(v);
            return 0x100000000ULL | (uint64_t)obj->class_id;
        }
        if (subtag == W_SUBTAG_CLASS) {
            WClass *klass = (WClass *)w_as_ptr(v);
            return 0x200000000ULL | (uint64_t)klass->class_id;
        }
        if (subtag == W_SUBTAG_GENERIC) {
            uint8_t type = *(uint8_t *)w_as_ptr(v);
            return 0x80u | (uint64_t)type;
        }
        return subtag;
    }
    if (hi < 0xFFF9) return 0xFF;                       /* double */
    /* W_TAG_PACKED (hi=0xFFFE) holds 8 packed-value subtypes (color,
     * complex, rational, NODE, date, ipv4, …) that need distinct
     * dispatch keys so each can register its own class. Map subtype
     * N → 0xE0 | N (range 0xE0..0xE7 — currently unused by other
     * type tags, which sit at 0xF9..0xFC). */
    if (hi == 0xFFFE) {
        uint64_t subtype = (v >> 45) & 0x7;
        /* W_PACKED_NODE (subtype 3): dispatch per-AST-kind so each kind
         * routes to its own specialized class (Call, Var, …) rather than
         * collapsing every node to a single Node class. The kind subtag
         * (bits 36-43) is folded into a wide key in the 0x4_0000_0000
         * range — distinct from instances (0x1…), classes (0x2…), and the
         * flat 8-bit tag/subtag keys — so the inline cache distinguishes
         * Call from Var. The node-kind dispatch path resolves this key
         * via g_node_kind_class[kind] (see w_method_dispatch). */
        if (subtype == W_PACKED_NODE) {
            return 0x400000000ULL | (uint64_t)w_node_kind(v);
        }
        return 0xE0u | subtype;
    }
    /* W_TAG_CHAR (hi=0xFFFC) holds 4 lexical subtypes (Token, LexChar,
     * Slice, Char) that need distinct dispatch keys for the same reason.
     * Map subtype N (bits 47..46) → 0xD0 | N (range 0xD0..0xD3 — free
     * range, no overlap with the 0xE0..0xE7 packed range or the
     * 0xF9..0xFF tagged range). */
    if (hi == 0xFFFC) {
        return 0xD0u | (uint64_t)((v >> 46) & 0x3);
    }
    return (uint64_t)(hi & 0xFF);                       /* tagged: int=0xFA, string=0xF9 */
}

/* ---- Type class table: dispatch key → class_id for Tungsten-defined methods ---- */
static uint16_t g_type_class[256] = {0};

static void w_public_type_class_register(uint8_t key, WClass *klass) {
    /* These keys intentionally expose only method facades. Packed Body uses
     * Array as its public identity and is resolved/cached by __w_type below. */
    if (key == W_SUBTAG_ATOMIC || key == (0x80u | W_TYPE_THREAD) ||
        key == (0x80u | W_TYPE_CHANNEL) || key == 0xE6)
        return;
    WValue class_value = w_box_ptr(klass, W_SUBTAG_CLASS);
    if (key == 0xF9) {
        if (strcmp(klass->name, "String") == 0)
            w_public_class_cache(0x0F9, class_value);
        else if (strcmp(klass->name, "Symbol") == 0)
            w_public_class_cache(0x1F9, class_value);
        return;
    }
    /* Most dispatch keys admit source aliases whose class name is not the
     * public __w_type name (Array/ByteArray/BoolArray is one concrete set).
     * Registration therefore invalidates both payload-parity pages and lets
     * the next public query apply the existing name check before caching. */
    g_public_type_class[key].resolved = 0;
    g_public_type_class[0x100u | key].resolved = 0;
}

void w_type_class_register(uint8_t dispatch_key, uint16_t class_id) {
    g_type_class[dispatch_key] = class_id + 1;
    if (g_class_table[class_id])
        w_public_type_class_register(dispatch_key, g_class_table[class_id]);
}

void w_type_class_register_wv(int32_t dispatch_key, WValue klass) {
    WClass *c = as_class(klass);
    uint8_t key = (uint8_t)(dispatch_key & 0xFF);
    g_type_class[key] = c->class_id + 1;
    w_public_type_class_register(key, c);
}

/* ---- .class / .class_name ----
 * w_class_of(v) returns the runtime class as a class-tagged WValue;
 * w_class_name(v) returns the class name as a string. Used by the
 * compiler lowering intercept for `obj.class` / `obj.class_name`.
 *
 * Resolution order:
 *   1. If v is itself a class, return it (class.class == self).
 *   2. If v is an instance, use WObject.class_id directly.
 *   3. Try the exact public-identity cache, independently of method facades.
 *   4. On a cold cache miss, accept g_type_class only if its class name agrees
 *      with __w_type(v), then cache that exact public result.
 *   5. Fallback: find a registered class whose name matches __w_type(v).
 *      Lets `4.class` return @class.Integer even when Integer hasn't
 *      (yet) registered a dispatch key. */
/* Lazy singleton for the "Class" class — what .class returns when the
 * receiver is itself a class. Created on first call so we don't pay
 * boot cost on programs that never touch .class. Cached in g_class_table
 * via name lookup so any later `+ Class` declaration reuses the same id. */
static WClass *g_class_class = NULL;
static WClass *class_class_singleton(void) {
    if (g_class_class) return g_class_class;
    for (int i = 0; i < g_next_class_id; i++) {
        WClass *k = g_class_table[i];
        if (k && strcmp(k->name, "Class") == 0) { g_class_class = k; return k; }
    }
    WValue v = w_class_new("Class", W_NIL);
    g_class_class = (WClass *)w_as_ptr(v);
    return g_class_class;
}

WValue w_class_of(WValue v) {
    if (w_is_class(v)) return w_box_ptr(class_class_singleton(), W_SUBTAG_CLASS);
    if (w_is_instance(v)) {
        WObject *obj = (WObject *)w_as_ptr(v);
        if (g_class_table[obj->class_id]) return w_box_ptr(g_class_table[obj->class_id], W_SUBTAG_CLASS);
    }
    uint64_t key = w_dispatch_key(v);
    /* Packed AST bodies use their own dispatch key so their read-only
     * Tungsten methods can bypass Array storage. That representation detail
     * is deliberately not public type identity: compiler code has always
     * treated AST child lists as Arrays (see __w_type above). Skip the Body
     * type-class registration here so `.class` follows that Array facade too.
     * Method dispatch still uses the 0xE6 key in w_method_dispatch. */
    int cacheable = !w_is_body(v) && key < 256;
    unsigned public_slot = 0;
    if (cacheable) {
        public_slot = (unsigned)key | ((unsigned)(v & 1u) << 8);
        WPublicClassEntry *cached = &g_public_type_class[public_slot];
        if (cached->resolved) return cached->value;
    }
    WValue type_name = __w_type(v);
    const char *want = as_str(type_name);
    if (cacheable) {
        uint16_t cid_slot = g_type_class[key];
        if (cid_slot) {
            WClass *klass = g_class_table[cid_slot - 1];
            if (klass && strcmp(klass->name, want) == 0) {
                WValue result = w_box_ptr(klass, W_SUBTAG_CLASS);
                w_public_class_cache(public_slot, result);
                return result;
            }
        }
    }
    for (int i = 0; i < g_next_class_id; i++) {
        WClass *k = g_class_table[i];
        if (k && strcmp(k->name, want) == 0) {
            WValue result = w_box_ptr(k, W_SUBTAG_CLASS);
            if (cacheable) w_public_class_cache(public_slot, result);
            return result;
        }
    }
    /* No class with this name registered (thin program that never autoloaded
     * the core class). Create a stub so `.class` is total — mirrors the
     * tree-walk interpreter, which conjures the same stub on demand. */
    if (strcmp(want, "Unknown") != 0) {
        WValue result = w_class_new(want, W_NIL);
        if (cacheable) w_public_class_cache(public_slot, result);
        return result;
    }
    if (cacheable) w_public_class_cache(public_slot, W_NIL);
    return W_NIL;
}

WValue w_class_name(WValue v) {
    if (w_is_class(v)) return w_string("Class");
    return __w_type(v);
}

/* ---- Node-kind class table: AST kind → class_id ----
 * Packed AST nodes dispatch per-kind (w_dispatch_key returns
 * 0x4_0000_0000 | kind). Each [slab] class (Call, Var, …) registers
 * here for its kind so method calls on a node route to the specialized
 * class. Indexed by the 8-bit kind id (0..255 covers all AST kinds).
 * Slot stores class_id + 1 so 0 means "unregistered". */
static uint16_t g_node_kind_class[256] = {0};

void w_node_kind_class_register_wv(int32_t kind, WValue klass) {
    WClass *c = as_class(klass);
    g_node_kind_class[kind & 0xFF] = c->class_id + 1;
}

static WMethod *w_type_class_method(uint16_t class_id, WValue name, int argc) {
    WMethod *m = w_method_lookup_arity(g_class_table[class_id], name, argc + 1);
    if (!m) m = w_method_lookup(g_class_table[class_id], name);
    return m;
}

static WValue w_type_class_method_call(WMethod *m, WValue recv, WArray *args) {
    int expected = m->arity - 1;
    WValue a[8];
    for (int i = 0; i < expected && i < 8; i++)
        a[i] = (i < args->size) ? args->slots[i] : W_NIL;
    typedef WValue (*fn0)(WValue);
    typedef WValue (*fn1)(WValue, WValue);
    typedef WValue (*fn2)(WValue, WValue, WValue);
    typedef WValue (*fn3)(WValue, WValue, WValue, WValue);
    typedef WValue (*fn4)(WValue, WValue, WValue, WValue, WValue);
    switch (expected) {
        case 0: return ((fn0)m->fn_ptr)(recv);
        case 1: return ((fn1)m->fn_ptr)(recv, a[0]);
        case 2: return ((fn2)m->fn_ptr)(recv, a[0], a[1]);
        case 3: return ((fn3)m->fn_ptr)(recv, a[0], a[1], a[2]);
        case 4: return ((fn4)m->fn_ptr)(recv, a[0], a[1], a[2], a[3]);
        default: return W_UNDEF;
    }
}

static WValue w_type_class_dispatch(uint16_t class_id, WValue recv, WValue name, WArray *args) {
    typedef WValue (*mm_fn1)(WValue, WValue);
    typedef WValue (*mm_fn2)(WValue, WValue, WValue);
    WMethod *m = w_type_class_method(class_id, name, args->size);
    if (!m) {
        /* Ruby-style method_missing fallback: when the named method
         * isn't found anywhere in the class tree, walk the tree again
         * for method_missing (getter) / method_missing_set (setter).
         * Scans by C-string content rather than via w_method_lookup(
         * w_symbol(...)) because a freshly-synthesized symbol doesn't
         * share the slab-interned identity (or splitmix hash) of the
         * symbol stored at class-registration time, so the hash-probe +
         * w_hash_key_eq path can miss. The method table is small. */
        const char *nm = as_str(name);
        size_t nm_len = nm ? strlen(nm) : 0;
        int is_setter = (args->size == 1 && nm_len > 0 && nm[nm_len - 1] == '=');
        const char *mm_target = is_setter ? "method_missing_set" : "method_missing";
        WMethod *mm = NULL;
        for (WClass *k = g_class_table[class_id]; k && !mm; k = k->superclass) {
            for (int i = 0; i < k->method_capacity; i++) {
                if (k->methods[i].name != 0) {
                    const char *mn = as_str(k->methods[i].name);
                    if (mn && strcmp(mn, mm_target) == 0) { mm = &k->methods[i]; break; }
                }
            }
        }
        if (is_setter) {
            if (mm && mm->arity == 3) {
                char field_buf[256];
                size_t fl = nm_len - 1;
                if (fl >= sizeof(field_buf)) fl = sizeof(field_buf) - 1;
                memcpy(field_buf, nm, fl);
                field_buf[fl] = '\0';
                return ((mm_fn2)mm->fn_ptr)(recv, w_symbol(field_buf), args->slots[0]);
            }
        } else {
            if (mm && mm->arity == 2) {
                /* Pass the field name as a SYMBOL, mirroring the setter
                 * branch above: method_missing bodies index symbol-keyed
                 * tables (ast.w's sparse meta), and a raw method-name
                 * string never matches a symbol key. */
                char field_buf[256];
                size_t fl = nm_len;
                if (fl >= sizeof(field_buf)) fl = sizeof(field_buf) - 1;
                memcpy(field_buf, nm, fl);
                field_buf[fl] = '\0';
                return ((mm_fn1)mm->fn_ptr)(recv, w_symbol(field_buf));
            }
        }
        return W_UNDEF;
    }
    return w_type_class_method_call(m, recv, args);
}

static inline WValue w_try_type_class_dispatch(WValue recv, WValue name, WArray *args) {
    uint64_t key = w_dispatch_key(recv);
    if (key >= 256) return W_UNDEF;
    uint16_t cid_slot = g_type_class[key];
    if (!cid_slot) return W_UNDEF;
    return w_type_class_dispatch(cid_slot - 1, recv, name, args);
}

/* Array builtin wrappers (uniform signature for IC) */
static WValue w_ic_array_push(WValue r, WValue *a, int c) {
    if (c < 1) die("push requires 1 argument");
    return w_array_push(r, a[0]);
}
static WValue w_ic_array_pop(WValue r, WValue *a, int c)     { (void)a; (void)c; return w_array_pop(r); }
/* Phase 7+d (#62 fix): use array_slot_load_decoded for the typed-array
 * cases (ebits ∈ {1, 4, 8, 16, 32, -32, -64} — anything packed narrower
 * than WValue). The earlier slots[i] direct-index was correct only for
 * ebits == 64/65 (WValue-stride storage); on packed arrays it read
 * misaligned bytes as a WValue and could fault past the allocation. */
static WValue w_ic_array_shift(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    WArray *arr = as_array(r);
    if (arr->size == 0) return W_NIL;
    WValue first = array_slot_load_decoded(arr, 0);
    arr->start++;
    arr->size--;
    return first;
}
static WValue w_ic_array_get(WValue r, WValue *a, int c) {
    (void)c;
    return w_array_get(r, a[0]);
}
static WValue w_ic_array_set(WValue r, WValue *a, int c) {
    (void)c;
    return w_array_set(r, a[0], a[1]);
}
/* Phase 7+c: unchecked variants — `[]` and `[]=` from Phase 6a's split.
 * The bounds-checked w_ic_array_get / _set above stay for `.get` / `.set`. */
static WValue w_ic_array_idx(WValue r, WValue *a, int c) {
    (void)c;
    return w_array_idx(r, a[0]);
}
static WValue w_ic_array_idxset(WValue r, WValue *a, int c) {
    (void)c;
    return w_array_idxset(r, a[0], a[1]);
}
static WValue w_ic_array_clear(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    WArray *arr = (WArray *)w_as_ptr(r);
    arr->start = 0;
    arr->size = 0;
    return r;
}
static WValue w_ic_array_include(WValue r, WValue *a, int c) {
    (void)c;
    WArray *arr = as_array(r);
    /* Phase 6.5 (#59) typed-array SIMD fast path. */
    if (arr->ebits == 1 && (a[0] == W_TRUE || a[0] == W_FALSE) && (arr->start & 7) == 0) {
        int64_t idx = (a[0] == W_TRUE)
            ? w_u1_index_set((const uint8_t *)arr->slots + (arr->start >> 3), arr->size)
            : w_u1_index_unset((const uint8_t *)arr->slots + (arr->start >> 3), arr->size);
        return idx < 0 ? W_FALSE : W_TRUE;
    }
    if (arr->ebits == 65 && w_is_int(a[0])) {
        int64_t idx = w_u64_scan_eq((const uint64_t *)arr->slots + arr->start,
                                     arr->size, (uint64_t)a[0]);
        return idx < 0 ? W_FALSE : W_TRUE;
    }
    if (w_is_int(a[0])) {
        int64_t needle = w_as_int(a[0]);
        if (arr->ebits == 8 && needle >= 0 && needle <= 255) {
            int64_t idx = w_byte_scan_eq_threaded((const uint8_t *)arr->slots + arr->start,
                                         arr->size, (uint8_t)needle);
            return idx < 0 ? W_FALSE : W_TRUE;
        }
        if (arr->ebits == 16 && needle >= -32768 && needle <= 65535) {
            int64_t idx = w_u16_scan_eq_threaded((const uint16_t *)arr->slots + arr->start,
                                         arr->size, (uint16_t)needle);
            return idx < 0 ? W_FALSE : W_TRUE;
        }
        if (arr->ebits == 32 && needle >= INT32_MIN && needle <= UINT32_MAX) {
            int64_t idx = w_u32_scan_eq_threaded((const uint32_t *)arr->slots + arr->start,
                                         arr->size, (uint32_t)needle);
            return idx < 0 ? W_FALSE : W_TRUE;
        }
    }
    /* Polymorphic / non-u8 path: arr->slots is WValue* only when ebits=64
     * (the w64 polymorphic bucket). For typed arrays, elements are packed
     * narrower than WValue, so direct slots[] indexing reads garbage and
     * can fault past the allocation. Use the array-tier accessor. */
    if (arr->ebits == 65 || arr->ebits == 64) {
        for (int32_t i = 0; i < arr->size; i++)
            if (w_eq(arr->slots[arr->start + i], a[0]) == W_TRUE) return W_TRUE;
        return W_FALSE;
    }
    for (int32_t i = 0; i < arr->size; i++)
        if (w_eq(array_slot_load_decoded(arr, i), a[0]) == W_TRUE) return W_TRUE;
    return W_FALSE;
}

/* Phase 7+f: typed-array math + view methods migrated from cascade. */
static WValue w_ic_array_fill(WValue r, WValue *a, int c) {
    if (c < 1) die("fill requires 1 argument");
    return w_array_fill(r, a[0]);
}
static WValue w_ic_array_view(WValue r, WValue *a, int c) {
    if (c < 1) die("view requires 1 argument");
    return w_array_reinterpret(r, w_as_int(a[0]));
}
