/* Phase 7+q: `string =~ regex` and `string.match?(regex)` swap so the
 * regex receives the call. Mirrors the cascade's pre-7+g behavior. */
static WValue w_ic_string_matchop(WValue r, WValue *a, int c) {
    if (c < 1 || !w_is_regex(a[0]))
        dief("=~ requires a Regex argument");
    return w_regex_match(a[0], r);
}
/* Phase 7+h: String UTF-8 / parse / mutate / convert. */
static WValue w_ic_string_chars(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    WValue result = w_array_new_empty();
    const unsigned char *p = (const unsigned char *)str;
    size_t remaining = str_len;
    while (remaining > 0) {
        int clen = 1;
        if (*p >= 0xF0) clen = 4;
        else if (*p >= 0xE0) clen = 3;
        else if (*p >= 0xC0) clen = 2;
        if ((size_t)clen > remaining) clen = (int)remaining;
        char cbuf[5];
        memcpy(cbuf, p, clen);
        cbuf[clen] = '\0';
        w_array_push(result, w_string(cbuf));
        p += clen;
        remaining -= clen;
    }
    return result;
}

/* Reverse by codepoint, not by byte — a byte-reverse would scramble every
 * multi-byte UTF-8 character (mirrors the codepoint-boundary walk in
 * w_ic_string_chars just above). */
static WValue w_ic_string_reverse(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    char *out = malloc(str_len + 1);
    const unsigned char *p = (const unsigned char *)str;
    size_t remaining = str_len;
    size_t write_pos = str_len;
    while (remaining > 0) {
        int clen = 1;
        if (*p >= 0xF0) clen = 4;
        else if (*p >= 0xE0) clen = 3;
        else if (*p >= 0xC0) clen = 2;
        if ((size_t)clen > remaining) clen = (int)remaining;
        write_pos -= clen;
        memcpy(out + write_pos, p, clen);
        p += clen;
        remaining -= clen;
    }
    out[str_len] = '\0';
    WValue result = w_string_n(out, str_len);
    free(out);
    return result;
}

static WValue w_ic_string_codes(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    /* Pre-count codepoints for exact allocation */
    size_t count = 0;
    const unsigned char *scan = (const unsigned char *)str;
    size_t scan_rem = str_len;
    while (scan_rem > 0) {
        int clen;
        if (*scan < 0x80) clen = 1;
        else if (*scan < 0xE0) clen = 2;
        else if (*scan < 0xF0) clen = 3;
        else clen = 4;
        if ((size_t)clen > scan_rem) clen = (int)scan_rem;
        scan += clen;
        scan_rem -= clen;
        count++;
    }
    WValue result = w_array_new(64, (int64_t)count);
    WArray *ta = (WArray *)w_as_ptr(result);
    ta->size = (int64_t)count;
    int64_t *data = (int64_t *)ta->slots;
    const unsigned char *p = (const unsigned char *)str;
    size_t remaining = str_len;
    size_t idx = 0;
    while (remaining > 0) {
        uint32_t cp;
        int clen;
        if (*p < 0x80)        { cp = *p;                 clen = 1; }
        else if (*p < 0xE0)   { cp = (*p & 0x1F) << 6;   clen = 2; }
        else if (*p < 0xF0)   { cp = (*p & 0x0F) << 12;  clen = 3; }
        else                  { cp = (*p & 0x07) << 18;  clen = 4; }
        for (int k = 1; k < clen && k < (int)remaining; k++)
            cp |= (p[k] & 0x3F) << (6 * (clen - 1 - k));
        if ((size_t)clen > remaining) clen = (int)remaining;
        data[idx++] = (int64_t)w_box_char(cp);
        p += clen;
        remaining -= clen;
    }
    return result;
}
static WValue w_ic_string_lchs(WValue r, WValue *a, int c) {
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    if (c > 0 && w_is_string(a[0])) {
        const char *lang = as_str(a[0]);
        int bits = 64;
        if (c >= 2) {
            if (!w_is_int(a[1])) die("lchs: bits argument must be an integer (16, 32, or 64)");
            bits = (int)w_as_int(a[1]);
            if (bits != 16 && bits != 32 && bits != 64)
                dief("lchs: bits must be 16, 32, or 64 (got %d)", bits);
        }
        const uint8_t *lang_flags = w_load_lang_flags(lang, bits);
        if (lang_flags) {
            if (bits == 64) return w_string_to_lexchars_lang(str, str_len, lang_flags);
            if (bits == 32) return w_string_to_lex32_lang(str, str_len, lang_flags);
            if (bits == 16) {
                const uint8_t *lex64 = w_load_lang_flags(lang, 64);
                return w_string_to_lex16_lang(str, str_len, lang_flags, lex64);
            }
        }
    }
    return w_string_to_lexchars(str, str_len);
}
static WValue w_ic_string_bytes(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    WValue result = w_array_new_empty();
    for (size_t i = 0; i < str_len; i++)
        w_array_push(result, w_int((uint8_t)str[i]));
    return result;
}
static WValue w_ic_string_slice(WValue r, WValue *a, int c) {
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    if (c >= 2) {
        int64_t start = w_as_int(a[0]);
        int64_t len = w_as_int(a[1]);
        if (start < 0) start = (int64_t)str_len + start;
        if (start < 0) start = 0;
        if (start >= (int64_t)str_len) return w_string("");
        if (len < 0) len = 0;
        if (start + len > (int64_t)str_len) len = (int64_t)str_len - start;
        char *result = malloc(len + 1);
        memcpy(result, str + start, len);
        result[len] = '\0';
        return w_string_take(result, len);
    }
    if (c >= 1) {
        int64_t start = w_as_int(a[0]);
        if (start < 0) start = (int64_t)str_len + start;
        if (start < 0 || start >= (int64_t)str_len) return w_string("");
        char ch[2] = {str[start], '\0'};
        return w_string(ch);
    }
    return W_NIL;
}
static WValue w_ic_string_strip(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    return w_string_trim_ascii(r, 1, 1);
}
static WValue w_ic_string_ltrim(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    return w_string_trim_ascii(r, 1, 0);
}
static WValue w_ic_string_rtrim(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    return w_string_trim_ascii(r, 0, 1);
}
static WValue w_ic_string_ord(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    if (str_len == 0) return w_int(0);
    unsigned char ch = (unsigned char)str[0];
    uint32_t cp;
    if (ch < 0x80) cp = ch;
    else if (ch < 0xE0) {
        cp = (ch & 0x1F) << 6;
        if (str_len > 1) cp |= ((unsigned char)str[1]) & 0x3F;
    } else if (ch < 0xF0) {
        cp = (ch & 0x0F) << 12;
        if (str_len > 1) { cp |= (((unsigned char)str[1]) & 0x3F) << 6;
            if (str_len > 2) cp |= ((unsigned char)str[2]) & 0x3F; }
    } else {
        cp = (ch & 0x07) << 18;
        if (str_len > 1) { cp |= (((unsigned char)str[1]) & 0x3F) << 12;
            if (str_len > 2) { cp |= (((unsigned char)str[2]) & 0x3F) << 6;
                if (str_len > 3) cp |= ((unsigned char)str[3]) & 0x3F; } }
    }
    return w_int((int64_t)cp);
}
static WValue w_ic_string_to_i(WValue r, WValue *a, int c) {
    int base = 10;
    if (c >= 1 && w_is_int(a[0])) base = (int)w_as_int(a[0]);
    return w_int(strtoll(as_str(r), NULL, base));
}
static WValue w_ic_string_to_f(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    return w_float(atof(as_str(r)));
}
static WValue w_ic_string_to_sym(WValue r, WValue *a, int c) {
    (void)a; (void)c;
    return w_str_to_sym(r);
}
static WValue w_ic_string_split(WValue r, WValue *a, int c) {
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    const char *sep = " ";
    size_t sep_len = 1;
    char sep_buf[6];
    if (c > 0) w_str_data(a[0], sep_buf, &sep, &sep_len);
    if (sep_len == 1) return w_string_split_byte(r, (uint8_t)sep[0]);
    WValue result = w_array_new_empty();
    const char *p = str;
    while (*p) {
        const char *found = strstr(p, sep);
        if (!found) { w_array_push(result, w_string(p)); break; }
        size_t chunk = found - p;
        char *part = malloc(chunk + 1);
        memcpy(part, p, chunk);
        part[chunk] = '\0';
        w_array_push(result, w_string_take(part, chunk));
        p = found + sep_len;
        if (*p == '\0') w_array_push(result, w_string(""));
    }
    return result;
}
static WValue w_ic_string_replace(WValue r, WValue *a, int c) {
    if (c < 2) die("replace requires 2 arguments");
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    const char *old_s = as_str(a[0]);
    const char *new_s = as_str(a[1]);
    size_t old_len = strlen(old_s);
    size_t new_len = strlen(new_s);
    int count = 0;
    const char *p = str;
    while ((p = strstr(p, old_s)) != NULL) { count++; p += old_len; }
    size_t result_len = strlen(str) + count * (new_len - old_len);
    char *result = malloc(result_len + 1);
    char *out = result;
    p = str;
    while (*p) {
        const char *found = strstr(p, old_s);
        if (!found) { strcpy(out, p); break; }
        size_t chunk = found - p;
        memcpy(out, p, chunk);
        out += chunk;
        memcpy(out, new_s, new_len);
        out += new_len;
        p = found + old_len;
    }
    result[result_len] = '\0';
    return w_string_take(result, result_len);
}
static WValue w_ic_string_index(WValue r, WValue *a, int c) {
    if (c < 1) die("index requires 1 argument");
    char buf[6]; const char *str; size_t str_len;
    w_str_data(r, buf, &str, &str_len);
    char nbuf[6]; const char *needle; size_t needle_len;
    w_str_data(a[0], nbuf, &needle, &needle_len);
    size_t offset = 0;
    if (c >= 2) {
        int64_t off = w_as_int(a[1]);
        if (off < 0 || (size_t)off > str_len) return W_NIL;
        offset = (size_t)off;
    }
    if (needle_len == 0) return w_int((int64_t)offset);
    if (needle_len == 1) {
        int64_t rel = w_byte_scan_eq((const uint8_t *)str + offset,
                                     (int64_t)(str_len - offset), (uint8_t)needle[0]);
        if (rel >= 0) return w_int((int64_t)offset + rel);
        return W_NIL;
    }
    const char *found = strstr(str + offset, needle);
    if (found) return w_int((int64_t)(found - str));
    return W_NIL;
}
WValue w_string_rindex(WValue recv, WValue needle_v, WValue pos_v); /* forward */
static WValue w_ic_string_rindex(WValue r, WValue *a, int c) {
    if (c < 1) die("rindex requires 1 argument");
    return w_string_rindex(r, a[0], c >= 2 ? a[1] : W_NIL);
}

/* ---- Int#prime? — tiered deterministic primality ----
 * Integer literals are NaN-boxed primitives with no class pointer, so
 * `n.prime?` dispatches here through the Int IC table (exactly like gcd/sqrt)
 * rather than to the `.w` method body in core/numeric/int.w. Tiers, fastest-
 * first by magnitude:
 *   • small-prime screen   — trial by the primes ≤ 37; settles every n < 1681.
 *   • prime-factor scan    — up to √n, for n ≤ 10⁶, using exact reciprocal
 *     divisibility by prime candidates (no hardware division in the hot loop).
 *     Profiling selects a conservative, mixed-distribution 10⁶ boundary.
 *   • Miller-Rabin (u64)    — O(log n) Montgomery arithmetic (division-free): a
 *     single hashed Forišek–Jančina base for n < 2³² (one round, exact), then a
 *     minimal deterministic witness ladder (3→4→5→6→7 bases) up to 2⁶⁴.
 *   • BPSW (bigint)         — for n ≥ 2⁶⁴: 7-base Miller-Rabin on BigInt WValues
 *     THEN a strong Lucas test (Baillie-PSW). The MR witness set is deterministic
 *     — an exact proof — for every n < 3.317·10²⁴ (Sinclair); above that the
 *     strong Lucas pass makes it BPSW, which has no known counterexample at any
 *     size (the two tests fail on near-disjoint pseudoprime families).
 * Mersenne fast path: a bigint of the form 2^p-1 skips Miller-Rabin entirely
 * and takes the Lucas-Lehmer test (w_prime_test_lucas_lehmer) — one chain of
 * p-2 modular squarings with a division-free Mersenne reduction, exact at any
 * magnitude and ~25-30× faster than 7-base bigint MR at these sizes. */
