static WValue w_ic_mmap_view_at(WValue r, WValue *a, int c) {
    if (c < 3) die("Mmap#view_at requires (byte_offset, ebits, n_elements)");
    int64_t byte_offset = w_as_int(a[0]);
    int64_t ebits;
    if (w_is_int(a[1])) {
        ebits = w_as_int(a[1]);
    } else if (w_is_symbol(a[1])) {
        const char *sym = as_str(a[1]);
        if      (strcmp(sym, "u1")  == 0) ebits = 1;
        else if (strcmp(sym, "u4")  == 0) ebits = 4;
        else if (strcmp(sym, "i4")  == 0) ebits = -4;
        else if (strcmp(sym, "u8")  == 0) ebits = 8;
        else if (strcmp(sym, "i8")  == 0) ebits = 108;
        else if (strcmp(sym, "u16") == 0) ebits = 16;
        else if (strcmp(sym, "i16") == 0) ebits = 116;
        else if (strcmp(sym, "u32") == 0) ebits = 32;
        else if (strcmp(sym, "i32") == 0) ebits = -32;
        else if (strcmp(sym, "u64") == 0) ebits = 64;
        else if (strcmp(sym, "i64") == 0) ebits = -64;
        else if (strcmp(sym, "f32") == 0) ebits = -32;
        else if (strcmp(sym, "f64") == 0) ebits = -64;
        else if (strcmp(sym, "bf16") == 0) ebits = -116;
        else if (strcmp(sym, "f8_e4m3") == 0) ebits = -108;
        else if (strcmp(sym, "f8_e5m2") == 0) ebits = -109;
        else if (strcmp(sym, "f4_e2m1") == 0) ebits = -104;
        else die("Mmap#view_at: unknown ebits symbol");
    } else {
        die("Mmap#view_at: ebits must be a symbol or int");
    }
    int64_t n_elements = w_as_int(a[2]);
    return __w_mmap_view_at(r, byte_offset, (int)ebits, n_elements);
}

static WValue w_ic_int_times(WValue r, WValue *a, int c) {
    if (c < 1 || !w_is_closure(a[c - 1])) die("times requires a block");
    WClosure *cl = as_closure(a[c - 1]);
    int64_t val = w_as_int(r);
    for (int64_t i = 0; i < val; i++) call_closure_1(cl, w_int(i));
    return W_NIL;
}

