static WValue (*w_resolve_ic(uint64_t key, WValue name, WValue recv))(WValue, WValue*, int) {
    const WICEntry *table = NULL;
    switch (key) {
        case 0x0A: table = w_ic_array_table;   break;
        case 0xF9: table = w_ic_string_table;  break;
        case 0xFA: table = w_ic_int_table;     break;
        case 0xFF: table = w_ic_float_table;   break;
        case 0xFD:
            /* The 0xFFFD numeric tag is shared by decimal, currency, and
             * quantity. Only plain decimals own these IC handlers — the
             * handlers funnel through cmp_numeric_double, which die()s on a
             * currency/quantity receiver (e.g. `(2 m).round`). Send those to
             * the cascade instead, which dispatches their real methods. */
            if (is_currency_any(recv) || is_quantity_any(recv)) return NULL;
            table = w_ic_decimal_table; break;  /* 0xFFFD numeric (decimal) */
        case 0x05: table = w_ic_hash_table;    break;  /* Phase 7+l */
        case 0x01: table = w_ic_atomic_table;  break;  /* Phase 7+m */
        case 0x84: table = w_ic_channel_table; break;  /* 0x80 | W_TYPE_CHANNEL=4 */
        case 0x8B: table = w_ic_bigint_table;  break;  /* 0x80 | W_TYPE_BIGINT=11 */
        case 0x0B: table = w_ic_strbuf_table;  break;  /* W_SUBTAG_STRBUF (Phase 7+n) */
        case 0x07: table = w_ic_regex_table;   break;  /* W_SUBTAG_REGEX (Phase 7+o) */
        case 0x81: table = w_ic_thread_table;  break;  /* 0x80 | W_TYPE_THREAD=1 */
        case 0x83: table = w_ic_socket_table;  break;  /* 0x80 | W_TYPE_SOCKET=3 */
        case 0x91: table = w_ic_mmap_table;    break;  /* 0x80 | W_TYPE_MMAP=17 */
        case 0x92: table = w_ic_big_array_table;   break;  /* 0x80 | W_TYPE_BIG_ARRAY=18 (Phase 7+p) */
        case 0x09: table = w_ic_small_array_table; break;  /* W_SUBTAG_SMALL_ARRAY=9 */
        case 0xE5: table = w_ic_ipv4_table;        break;  /* packed IPv4 subtype 5 */
        case 0x85: table = w_ic_mac_table;         break;  /* 0x80 | W_TYPE_MAC=5 */
        case 0x86: table = w_ic_ipv6_table;        break;  /* 0x80 | W_TYPE_IPV6=6 */
        default: return NULL;
    }
    for (int i = 0; table[i].fn; i++)
        if (table[i].name == name) return table[i].fn;
    return NULL;
}

/* Forward declarations for slow-path lazy init (definitions live below
 * w_method_dispatch since they share the dispatch_ready flag). */
static _Atomic int w_dispatch_ready;
static void w_dispatch_init(void);

/* Resolve a Tungsten type-class method only when that method is the next
 * dispatch target. This mirrors w_method_dispatch's early ordering instead
 * of inferring the winner after the call: Closure#call and UUID#to_s keep
 * their dedicated runtime paths, while arrays and packed AST nodes use the
 * same specialized class slots as the dispatcher. A method_missing fallback
 * is intentionally not cacheable because its call shape differs from the
 * original method's shape. */
static WMethod *w_cacheable_type_class_method(WValue recv, WValue name,
                                               int argc, uint64_t key) {
    uint16_t cid_slot = 0;

    if (w_is_closure(recv) && name == WN_call) return NULL;

    if (w_is_array(recv)) {
        cid_slot = g_type_class[key];
    } else if (w_is_node(recv)) {
        cid_slot = g_node_kind_class[w_node_kind(recv) & 0xFF];
    } else if (key < 256) {
        if (name == WN_to_s && w_is_obj(recv) &&
            w_subtag(recv) == W_SUBTAG_UUID)
            return NULL;
        cid_slot = g_type_class[key];
    }

    if (!cid_slot) return NULL;
    WMethod *m = w_type_class_method(cid_slot - 1, name, argc);
    if (!m || m->arity < 1 || m->arity > 5) return NULL;
    return m;
}

/* Out-of-line slow path: cache miss → full dispatch + populate IC.
 * Only runs on first call per call site (or on type-change); the hot
 * fast path lives in w_method_call_cached below and is inlined into
 * every IR call site under LTO. */
__attribute__((visibility("hidden")))
WValue w_method_call_slow(WValue recv, WValue name, WValue *args_ptr, int argc,
                          WInlineCache *cache, uint64_t key) {
    /* Init IC tables on first slow-path entry. The cached fast path can
     * reach here before w_method_dispatch has ever run — without this,
     * IC names are all 0 and w_resolve_ic always misses, breaking any
     * method that has been migrated out of the cascade. */
    if (__builtin_expect(!atomic_load_explicit(&w_dispatch_ready, memory_order_acquire), 0))
        w_dispatch_init();

    /* Phase 7+a (#45): try IC resolve BEFORE the cascade. Builtin
     * methods registered in the per-type IC tables (Array, String, Int)
     * dispatch directly to their handler — no cascade walk on the
     * first call, just a populate-and-return. Methods not in any IC
     * table fall through to the cascade as before. */
    WValue (*builtin)(WValue, WValue*, int) = w_resolve_ic(key, name, recv);
    if (builtin) {
        cache->type_key = key;
        cache->fn_ptr = (void *)builtin;
        cache->arity = -1;
        return builtin(recv, args_ptr, argc);
    }

    WArray stack_args;
    stack_args.slots = args_ptr;
    stack_args.start = 0;
    stack_args.size = argc;
    stack_args.cap = argc;

    /* Cache the exact Tungsten method selected by type-class dispatch. Doing
     * this before the general dispatcher means we never populate from a
     * merely-present method that an earlier special path actually handled. */
    WMethod *type_method = w_cacheable_type_class_method(recv, name, argc, key);
    if (type_method) {
        cache->type_key = key;
        cache->fn_ptr = type_method->fn_ptr;
        cache->arity = type_method->arity - 1; /* subtract self */
        return w_type_class_method_call(type_method, recv, &stack_args);
    }

    WValue result = w_method_dispatch(recv, name, &stack_args, W_NIL);

    if (key >= 0x100 && w_is_instance(recv)) {
        /* Cache user class methods */
        WObject *obj = (WObject *)w_as_ptr(recv);
        WMethod *m = w_method_lookup_arity(g_class_table[obj->class_id], name, argc + 1);
        if (!m) m = w_method_lookup(g_class_table[obj->class_id], name);
        if (m) {
            cache->type_key = key;
            cache->fn_ptr = m->fn_ptr;
            cache->arity = m->arity - 1; /* subtract self */
        }
    } else if (w_is_class(recv) && !w_hash_key_eq(name, WN_new)) {
        /* Cache user-defined static methods. Constructors allocate before dispatch. */
        WClass *klass = (WClass *)w_as_ptr(recv);
        WMethod *m = w_static_method_lookup_arity(klass, name, argc + 1);
        if (!m) m = w_static_method_lookup(klass, name);
        if (m) {
            cache->type_key = key;
            cache->fn_ptr = m->fn_ptr;
            cache->arity = m->arity - 1; /* subtract class receiver */
        }
    }
    return result;
}

/* Inline-cached method dispatch — fast path. Plain `inline` lets LTO
 * decide; with thousands of dispatch sites in the self-hosted compiler,
 * forcing always_inline blows up IR size and quadratic-times the LTO
 * passes. The cache-miss path is out-of-line in w_method_call_slow above. */
inline
WValue w_method_call_cached(WValue recv, WValue name, WValue *args_ptr, int argc, WInlineCache *cache) {
    /* Flatten ropes before dispatch so IC sees a string type */
    if (__builtin_expect(w_is_rope(recv), 0)) recv = w_rope_flatten(recv);

    uint64_t key = w_dispatch_key(recv);

    /* Cache hit — direct call */
    if (__builtin_expect(key == cache->type_key && cache->fn_ptr != NULL, 1)) {
        if (cache->arity < 0) {
            return ((WValue(*)(WValue, WValue*, int))cache->fn_ptr)(recv, args_ptr, argc);
        }
        /* User method: dispatch by arity */
        int expected = cache->arity;
        WValue a[8];
        for (int i = 0; i < expected && i < 8; i++)
            a[i] = (i < argc) ? args_ptr[i] : W_NIL;
        typedef WValue (*fn0)(WValue);
        typedef WValue (*fn1)(WValue, WValue);
        typedef WValue (*fn2)(WValue, WValue, WValue);
        typedef WValue (*fn3)(WValue, WValue, WValue, WValue);
        typedef WValue (*fn4)(WValue, WValue, WValue, WValue, WValue);
        switch (expected) {
            case 0: return ((fn0)cache->fn_ptr)(recv);
            case 1: return ((fn1)cache->fn_ptr)(recv, a[0]);
            case 2: return ((fn2)cache->fn_ptr)(recv, a[0], a[1]);
            case 3: return ((fn3)cache->fn_ptr)(recv, a[0], a[1], a[2]);
            case 4: return ((fn4)cache->fn_ptr)(recv, a[0], a[1], a[2], a[3]);
            default: break;
        }
    }

    return w_method_call_slow(recv, name, args_ptr, argc, cache, key);
}

/* Zero-argument method dispatch gets its own entry point because it is the
 * most common dynamic call shape emitted by the compiler.  On a cached
 * source-method hit, the generic dispatcher still has to enter an argument
 * fill loop and switch on a runtime arity even though both the caller and the
 * selected method have no explicit arguments.  Keep the same cache lookup,
 * builtin-wrapper ABI, fallback behavior, and slow path, but make the arity-0
 * source-method case a single direct call.  The nil-filled cases preserve the
 * generic dispatcher's established behavior when a zero-argument call falls
 * back to a method with a larger arity. */
inline
WValue w_method_call_cached_0(WValue recv, WValue name, WInlineCache *cache) {
    /* Flatten ropes before dispatch so IC sees a string type. */
    if (__builtin_expect(w_is_rope(recv), 0)) recv = w_rope_flatten(recv);

    uint64_t key = w_dispatch_key(recv);

    if (__builtin_expect(key == cache->type_key && cache->fn_ptr != NULL, 1)) {
        if (cache->arity < 0) {
            return ((WValue(*)(WValue, WValue*, int))cache->fn_ptr)(recv, NULL, 0);
        }

        typedef WValue (*fn0)(WValue);
        typedef WValue (*fn1)(WValue, WValue);
        typedef WValue (*fn2)(WValue, WValue, WValue);
        typedef WValue (*fn3)(WValue, WValue, WValue, WValue);
        typedef WValue (*fn4)(WValue, WValue, WValue, WValue, WValue);

        if (__builtin_expect(cache->arity == 0, 1))
            return ((fn0)cache->fn_ptr)(recv);

        switch (cache->arity) {
            case 1: return ((fn1)cache->fn_ptr)(recv, W_NIL);
            case 2: return ((fn2)cache->fn_ptr)(recv, W_NIL, W_NIL);
            case 3: return ((fn3)cache->fn_ptr)(recv, W_NIL, W_NIL, W_NIL);
            case 4: return ((fn4)cache->fn_ptr)(recv, W_NIL, W_NIL, W_NIL, W_NIL);
            default: break;
        }
    }

    return w_method_call_slow(recv, name, NULL, 0, cache, key);
}

/* Every non-steady-state case reuses the canonical generic dispatcher. This
 * keeps pointer formation for the vector ABI out of the source-instance hot
 * helper and centralizes rope flattening, miss handling, nil padding, and
 * native-wrapper behavior in the already-tested implementation. */
__attribute__((noinline, cold))
static WValue w_method_call_cached_1_compat(
        WValue recv, WValue name, WValue arg, WInlineCache *cache) {
    return w_method_call_cached(recv, name, &arg, 1, cache);
}

/* Scalar argc-one cached dispatch for a proven exact source class owning the
 * target method. Its steady-state receiver is necessarily a WObject instance,
 * so compute that cache key directly instead of running the full polymorphic
 * WValue classifier. Conservative type metadata may still become stale across
 * control flow; the outlined generic path above preserves exact semantics in
 * that case. Cache contents stay in the canonical WInlineCache format. */
inline
WValue w_method_call_cached_1(WValue recv, WValue name, WValue arg,
                              WInlineCache *cache) {
    if (__builtin_expect(w_is_instance(recv), 1)) {
        WObject *obj = (WObject *)w_as_ptr(recv);
        uint64_t key = 0x100000000ULL | (uint64_t)obj->class_id;
        if (__builtin_expect(key == cache->type_key &&
                             cache->fn_ptr != NULL && cache->arity == 1, 1)) {
            return ((WValue(*)(WValue, WValue))cache->fn_ptr)(recv, arg);
        }
    }
    return w_method_call_cached_1_compat(recv, name, arg, cache);
}

/* Direct-call string builtins (bypass method dispatch) */

WValue w_string_count(WValue recv, WValue needle_v) {
    if (w_is_rope(recv)) recv = w_rope_flatten(recv);
    char _sbuf[6];
    const char *str;
    size_t str_len;
    w_str_data(recv, _sbuf, &str, &str_len);
    char _nbuf[6];
    const char *needle;
    size_t needle_len;
    w_str_data(needle_v, _nbuf, &needle, &needle_len);
    if (needle_len == 0) return w_int(0);
    if (needle_len == 1)
        return w_int(w_byte_scan_count_threaded((const uint8_t *)str, (int64_t)str_len, (uint8_t)needle[0]));
    int64_t count = 0;
    const char *p = str;
    while ((p = strstr(p, needle)) != NULL) {
        count++;
        p += needle_len;
    }
    return w_int(count);
}

WValue w_string_index(WValue recv, WValue needle_v, WValue offset_v) {
    if (w_is_rope(recv)) recv = w_rope_flatten(recv);
    char _sbuf[6];
    const char *str;
    size_t str_len;
    w_str_data(recv, _sbuf, &str, &str_len);
    char _nbuf[6];
    const char *needle;
    size_t needle_len;
    w_str_data(needle_v, _nbuf, &needle, &needle_len);
    size_t offset = 0;
    if (offset_v != W_NIL) {
        int64_t off = w_as_int(offset_v);
        if (off < 0 || (size_t)off > str_len) return W_NIL;
        offset = (size_t)off;
    }
    if (needle_len == 0) return w_int((int64_t)offset);
    if (needle_len == 1) {
        int64_t rel = w_byte_scan_eq((const uint8_t *)str + offset, (int64_t)(str_len - offset), (uint8_t)needle[0]);
        if (rel >= 0) return w_int((int64_t)offset + rel);
        return W_NIL;
    }
    const char *found = strstr(str + offset, needle);
    if (found) return w_int((int64_t)(found - str));
    return W_NIL;
}

/* Last occurrence of needle, mirroring w_string_index. Optional pos_v
 * caps the highest start index considered (Ruby rindex semantics). */
WValue w_string_rindex(WValue recv, WValue needle_v, WValue pos_v) {
    if (w_is_rope(recv)) recv = w_rope_flatten(recv);
    char _sbuf[6];
    const char *str;
    size_t str_len;
    w_str_data(recv, _sbuf, &str, &str_len);
    char _nbuf[6];
    const char *needle;
    size_t needle_len;
    w_str_data(needle_v, _nbuf, &needle, &needle_len);
    size_t limit = str_len;
    if (pos_v != W_NIL) {
        int64_t pos = w_as_int(pos_v);
        if (pos < 0) return W_NIL;
        if ((size_t)pos < limit) limit = (size_t)pos;
    }
    if (needle_len == 0) return w_int((int64_t)limit);
    if (needle_len > str_len) return W_NIL;
    size_t start = str_len - needle_len;
    if (limit < start) start = limit;
    for (size_t i = start + 1; i-- > 0; ) {
        if (memcmp(str + i, needle, needle_len) == 0) return w_int((int64_t)i);
    }
    return W_NIL;
}

WValue w_string_repeat(WValue recv, WValue count_v) {
    if (w_is_rope(recv)) recv = w_rope_flatten(recv);
    char _sbuf[6];
    const char *str;
    size_t str_len;
    w_str_data(recv, _sbuf, &str, &str_len);
    int64_t n = w_as_int(count_v);
    if (n < 0) die("repeat count must be non-negative");
    if (n == 0 || str_len == 0) return w_string("");
    size_t total = str_len * (size_t)n;
    if (total <= 5) {
        char tmp[6];
        for (size_t i = 0; i < total; i++) tmp[i] = str[i % str_len];
        tmp[total] = '\0';
        return w_box_inline_str(tmp, total);
    }
    /* Allocate WString directly — skip interning for large results */
    WString *ws = malloc(sizeof(WString) + total + 1);
    ws->len = total;
    memcpy(ws->data, str, str_len);
    /* Doubling copy: O(log n) memcpy calls instead of O(n) */
    size_t copied = str_len;
    while (copied < total) {
        size_t chunk = copied;
        if (chunk > total - copied) chunk = total - copied;
        memcpy(ws->data + copied, ws->data, chunk);
        copied += chunk;
    }
    ws->data[total] = '\0';
    return w_box_heap_str(ws);
}

static _Atomic int w_dispatch_ready = 0;
static pthread_once_t w_dispatch_once = PTHREAD_ONCE_INIT;

static void w_dispatch_init_once(void) {
    w_init_method_names();
    w_init_ic_tables();
    atomic_store_explicit(&w_dispatch_ready, 1, memory_order_release);
}

static void w_dispatch_init(void) {
    pthread_once(&w_dispatch_once, w_dispatch_init_once);
}

static WValue w_method_dispatch(WValue recv, WValue name, WArray *args, WValue args_arr) {
    (void)args_arr;
    if (__builtin_expect(!atomic_load_explicit(&w_dispatch_ready, memory_order_acquire), 0))
        w_dispatch_init();

    /* Rope: flatten and dispatch as string */
    if (w_is_rope(recv)) recv = w_rope_flatten(recv);

    /* Closures dispatch .call(args...) → invoke the closure */
    if (w_is_closure(recv) && name == WN_call) {
        if (args->size == 0) return w_closure_call_0(recv);
        if (args->size == 1) return w_closure_call_1(recv, args->slots[0]);
        if (args->size == 2) return w_closure_call_2(recv, args->slots[0], args->slots[1]);
        die("closure .call supports up to 2 arguments");
    }

    if (w_is_array(recv)) {
        WValue result = w_try_type_class_dispatch(recv, name, args);
        if (result != W_UNDEF) return result;
    }

    /* Phase 7+e: try IC table for migrated builtins. Lets w_method_call /
     * w_method_call_fast (which bypass the cached fast path) reach the
     * IC handlers without falling through to a stale cascade entry. */
    {
        uint64_t key = w_dispatch_key(recv);
        WValue (*builtin)(WValue, WValue*, int) = w_resolve_ic(key, name, recv);
        if (builtin) return builtin(recv, args->slots, args->size);
    }

    /* Array storage and numeric kernels live in w_ic_array_table. Header and
     * endpoint query leaves live in core/array.w; collection combinators
     * resolve through Enumerable. */

    /* Hash size, has_key?, keys, values, merge!, each, delete, get/idx, and
     * set/idxset live in w_ic_hash_table. Hash#map comes from Enumerable. */

    /* String/Symbol storage primitives (idx, case conversion,
     * UTF-8/parse/convert, =~, match?, etc.) remain in w_ic_string_table.
     * size, length, and empty? fall through to their Tungsten class. */

    /* Regex, Int.times, Socket, retained Mmap primitives, Atomic
     * cas/get/set/add, Channel send/close, and Thread join/kill use ICs.
     * The four bounded synchronization leaves fall through to core sources. */

    /* Phase 6i.1: ByteArray method dispatch removed — ByteArray is a
     * WArray<u8>. Header query leaves reach Array's Tungsten type class;
     * get/set/idx/idxset/copy/etc. use the standard array IC above.
     * WN_concat is likewise handled by the type-class table. */

    /* Phase 6i.1b: BoolArray dispatch removed — BoolArray is a WArray<u1>.
     * Query leaves reach Array's Tungsten type class; idx/idxset/each retain
     * the standard array path, whose ebits=1 cases convert bits ↔ Bool. */

    /* Phase 7+p: BigArray (key 0x92) and SmallArray (key 0x09) inline fast
     * paths live in their IC tables. Methods not in IC fall through here;
     * the global type-class dispatch at the bottom catches user-defined
     * trait methods (each, map, etc. from core/big_array.w / small_array.w). */

    /* Phase 7+f: typed-array storage/mutation methods (fill, view,
     * slice_view, data, raw_ptr, push, pop, shift, unshift, idx, idxset,
     * get, set, min, max, sum, fastsum, sumsq, dot, cross, scale, scale!,
     * cos, sin, sqrt, matvec_i8, matmul_i8, sort) live in the Array IC.
     * size/cap/empty?/first/last fall through to core/array.w. */

    /* Per-kind node dispatch: packed AST nodes route to their specialized
     * class via g_node_kind_class[kind]. w_type_class_dispatch walks the
     * Call→Node (etc.) superclass chain, so shared accessors on Node are
     * found through inheritance. */
    if (w_is_node(recv)) {
        uint16_t cid_slot = g_node_kind_class[w_node_kind(recv) & 0xFF];
        if (cid_slot) {
            WValue result = w_type_class_dispatch(cid_slot - 1, recv, name, args);
            if (result != W_UNDEF) return result;
        }
    }

    /* Type class dispatch: check if any Tungsten class is registered for this dispatch key */
    {
        uint64_t key = w_dispatch_key(recv);
        if (key < 256) {
            uint16_t cid_slot = g_type_class[key];
            if (cid_slot) {
                /* to_s on UUID needs C path for hex formatting */
                if (name == WN_to_s && w_is_obj(recv) && w_subtag(recv) == W_SUBTAG_UUID)
                    return w_uuid_to_s(recv);
                WValue result = w_type_class_dispatch(cid_slot - 1, recv, name, args);
                if (result != W_UNDEF) return result;
            }
        }
    }

    /* Object method dispatch */
    if (w_is_instance(recv)) {
        WObject *obj = as_object(recv);
        WMethod *m = w_method_lookup_arity(g_class_table[obj->class_id], name, args->size + 1);
        if (!m) m = w_method_lookup(g_class_table[obj->class_id], name);
        if (m) {
            /* Pad missing args with W_NIL (default parameters) and dispatch
             * based on declared arity, not caller-provided arg count. */
            int expected = m->arity - 1; /* subtract self */
            /* Implicit construction from the receiver's class: a one-param
             * method called with N>1 args builds its argument from the
             * receiver's own class when the constructor arity matches —
             * p.distance(2, 3, 4) â¡ p.distance(Point.new(2, 3, 4)). */
            if (expected == 1 && args->size > 1) {
                WClass *k = g_class_table[obj->class_id];
                if (w_method_lookup_arity(k, WN_new, args->size + 1)) {
                    WValue cls = w_box_ptr(k, W_SUBTAG_CLASS);
                    WValue inst = w_method_dispatch(cls, WN_new, args, args_arr);
                    typedef WValue (*ic_fn1)(WValue, WValue);
                    return ((ic_fn1)m->fn_ptr)(recv, inst);
                }
            }
            WValue a[8];
            for (int i = 0; i < expected && i < 8; i++)
                a[i] = (i < args->size) ? args->slots[i] : W_NIL;
            typedef WValue (*fn0)(WValue);
            typedef WValue (*fn1)(WValue, WValue);
            typedef WValue (*fn2)(WValue, WValue, WValue);
            typedef WValue (*fn3)(WValue, WValue, WValue, WValue);
            typedef WValue (*fn4)(WValue, WValue, WValue, WValue, WValue);
            typedef WValue (*fn5)(WValue, WValue, WValue, WValue, WValue, WValue);
            typedef WValue (*fn6)(WValue, WValue, WValue, WValue, WValue, WValue, WValue);
            typedef WValue (*fn7)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
            typedef WValue (*fn8)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
            switch (expected) {
                case 0: return ((fn0)m->fn_ptr)(recv);
                case 1: return ((fn1)m->fn_ptr)(recv, a[0]);
                case 2: return ((fn2)m->fn_ptr)(recv, a[0], a[1]);
                case 3: return ((fn3)m->fn_ptr)(recv, a[0], a[1], a[2]);
                case 4: return ((fn4)m->fn_ptr)(recv, a[0], a[1], a[2], a[3]);
                case 5: return ((fn5)m->fn_ptr)(recv, a[0], a[1], a[2], a[3], a[4]);
                case 6: return ((fn6)m->fn_ptr)(recv, a[0], a[1], a[2], a[3], a[4], a[5]);
                case 7: return ((fn7)m->fn_ptr)(recv, a[0], a[1], a[2], a[3], a[4], a[5], a[6]);
                case 8: return ((fn8)m->fn_ptr)(recv, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7]);
                default: die_method_arity("method", g_class_table[obj->class_id]->name, as_str(m->name), expected, 8); return W_NIL;
            }
        }
        if (name == WN_to_s) return w_to_s(recv);
    }

    /* Class method dispatch */
    if (w_is_class(recv)) {
        WClass *klass = as_class(recv);

        /* Socket.listen(host, port, backlog) */
        if (strcmp(klass->name, "Socket") == 0 && w_hash_key_eq(name, WN_listen)) {
            if (args->size < 2) die("Socket.listen requires at least host and port");
            const char *host = as_str(args->slots[0]);
            int port = (int)w_as_int(args->slots[1]);
            int backlog = (args->size > 2) ? (int)w_as_int(args->slots[2]) : 128;
            return w_socket_tcp_listen(host, port, backlog);
        }

        /* Socket.connect(host, port) */
        if (strcmp(klass->name, "Socket") == 0 && w_hash_key_eq(name, WN_connect)) {
            if (args->size < 2) die("Socket.connect requires host and port");
            const char *host = as_str(args->slots[0]);
            int port = (int)w_as_int(args->slots[1]);
            return w_socket_tcp_connect(host, port);
        }

        /* TLS.init() / TLS.load_cert(cert, key) */
        if (strcmp(klass->name, "TLS") == 0) {
            if (w_hash_key_eq(name, WN_init)) {
                return w_tls_init();
            }
            if (w_hash_key_eq(name, WN_load_cert)) {
                if (args->size < 2) die("TLS.load_cert requires cert_path and key_path");
                const char *cert = as_str(args->slots[0]);
                const char *key = as_str(args->slots[1]);
                return w_tls_load_cert(cert, key);
            }
        }

        /* Response.new(status, body) — fast path avoids strlen by using WString len.
           User-defined classes named Response still need normal constructor dispatch. */
        if (strcmp(klass->name, "Response") == 0 && w_hash_key_eq(name, WN_new) &&
            w_method_lookup(klass, WN_new) == NULL) {
            if (args->size < 2) die("Response.new requires status and body");
            return w_response_new_wv(args->slots[0], args->slots[1]);
        }


        /* ByteArray.new(length) */
        if (strcmp(klass->name, "ByteArray") == 0 && w_hash_key_eq(name, WN_new)) {
            int64_t len = (args->size > 0) ? w_as_int(args->slots[0]) : 0;
            return w_bytes_new(len);
        }

        /* BoolArray.new(length) — Phase 6i.1b: returns a bit-packed WArray<u1> */
        if (strcmp(klass->name, "BoolArray") == 0 && w_hash_key_eq(name, WN_new)) {
            int64_t len = (args->size > 0) ? w_as_int(args->slots[0]) : 0;
            return w_bool_array_new(len);
        }

        if (w_hash_key_eq(name, WN_new)) {
            WValue obj = w_object_new(recv);
            WMethod *m = w_method_lookup_arity(klass, WN_new, args->size + 1);
            if (!m) m = w_method_lookup(klass, WN_new);
            if (m) {
                int expected = m->arity - 1;
                WValue a[16];
                for (int i = 0; i < expected && i < 16; i++)
                    a[i] = (i < args->size) ? args->slots[i] : W_NIL;
                typedef WValue (*fn0)(WValue);
                typedef WValue (*fn1)(WValue, WValue);
                typedef WValue (*fn2)(WValue, WValue, WValue);
                typedef WValue (*fn3)(WValue, WValue, WValue, WValue);
                typedef WValue (*fn4)(WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn5)(WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn6)(WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn7)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn8)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn9)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn10)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn11)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn12)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn13)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn14)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn15)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                typedef WValue (*fn16)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
                switch (expected) {
                    case 0: ((fn0)m->fn_ptr)(obj); break;
                    case 1: ((fn1)m->fn_ptr)(obj, a[0]); break;
                    case 2: ((fn2)m->fn_ptr)(obj, a[0], a[1]); break;
                    case 3: ((fn3)m->fn_ptr)(obj, a[0], a[1], a[2]); break;
                    case 4: ((fn4)m->fn_ptr)(obj, a[0], a[1], a[2], a[3]); break;
                    case 5: ((fn5)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4]); break;
                    case 6: ((fn6)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5]); break;
                    case 7: ((fn7)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6]); break;
                    case 8: ((fn8)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7]); break;
                    case 9: ((fn9)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7], a[8]); break;
                    case 10: ((fn10)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7], a[8], a[9]); break;
                    case 11: ((fn11)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7], a[8], a[9], a[10]); break;
                    case 12: ((fn12)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7], a[8], a[9], a[10], a[11]); break;
                    case 13: ((fn13)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7], a[8], a[9], a[10], a[11], a[12]); break;
                    case 14: ((fn14)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7], a[8], a[9], a[10], a[11], a[12], a[13]); break;
                    case 15: ((fn15)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7], a[8], a[9], a[10], a[11], a[12], a[13], a[14]); break;
                    case 16: ((fn16)m->fn_ptr)(obj, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7], a[8], a[9], a[10], a[11], a[12], a[13], a[14], a[15]); break;
                    default: die_method_arity("constructor", klass->name, "new", expected, 16); break;
                }
            }
            return obj;
        }

        /* User-defined class (static) methods.
         * Arity includes __self (the class object), so user-visible param count = arity - 1.
         * Pass recv (the class WValue) as the first argument. */
        WMethod *sm = w_static_method_lookup_arity(klass, name, args->size + 1);
        if (!sm) sm = w_static_method_lookup(klass, name);
        if (sm) {
            int expected = sm->arity - 1;  /* subtract self */
            WValue a[8];
            for (int i = 0; i < expected && i < 8; i++)
                a[i] = (i < args->size) ? args->slots[i] : W_NIL;
            typedef WValue (*sfn1)(WValue);
            typedef WValue (*sfn2)(WValue, WValue);
            typedef WValue (*sfn3)(WValue, WValue, WValue);
            typedef WValue (*sfn4)(WValue, WValue, WValue, WValue);
            typedef WValue (*sfn5)(WValue, WValue, WValue, WValue, WValue);
            typedef WValue (*sfn6)(WValue, WValue, WValue, WValue, WValue, WValue);
            typedef WValue (*sfn7)(WValue, WValue, WValue, WValue, WValue, WValue, WValue);
            typedef WValue (*sfn8)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
            typedef WValue (*sfn9)(WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue, WValue);
            switch (expected) {
                case 0: return ((sfn1)sm->fn_ptr)(recv);
                case 1: return ((sfn2)sm->fn_ptr)(recv, a[0]);
                case 2: return ((sfn3)sm->fn_ptr)(recv, a[0], a[1]);
                case 3: return ((sfn4)sm->fn_ptr)(recv, a[0], a[1], a[2]);
                case 4: return ((sfn5)sm->fn_ptr)(recv, a[0], a[1], a[2], a[3]);
                case 5: return ((sfn6)sm->fn_ptr)(recv, a[0], a[1], a[2], a[3], a[4]);
                case 6: return ((sfn7)sm->fn_ptr)(recv, a[0], a[1], a[2], a[3], a[4], a[5]);
                case 7: return ((sfn8)sm->fn_ptr)(recv, a[0], a[1], a[2], a[3], a[4], a[5], a[6]);
                case 8: return ((sfn9)sm->fn_ptr)(recv, a[0], a[1], a[2], a[3], a[4], a[5], a[6], a[7]);
                default: die_method_arity("static method", klass->name, as_str(sm->name), expected, 8); return W_NIL;
            }
        }
    }

    /* ---- StringBuffer methods ---- */
    /* Phase 7+n: retained StringBuffer primitives (to_s, include?,
     * starts_with?) live in w_ic_strbuf_table; size is source-defined. */

    /* Universal to_s fallback for any type */
    if (name == WN_to_s) return w_to_s(recv);

    /* Global builtins callable from any context (bootstrapping fallback) */
    if ((w_hash_key_eq(name, WN_file_exists_q) || w_hash_key_eq(name, WN_file_q)) && args->size >= 1)
        return __w_file_exists(args->slots[0]);
    if (w_hash_key_eq(name, WN_read_file) && args->size >= 1)
        return __w_read_file(args->slots[0]);
    if (w_hash_key_eq(name, WN_write_file) && args->size >= 2)
        return __w_write_file(args->slots[0], args->slots[1]);

    /* Middle-dot multiply (mÂ·cÂ²): Â· on numeric-domain receivers is
     * multiplication. Vec/Mat classes define their own Â· (dot product),
     * which wins via normal class dispatch before this universal arm. */
    if (args->size >= 1) {
        const char *nm = as_str(name);
        if (nm[0] == (char)0xC2 && nm[1] == (char)0xB7 && nm[2] == 0 &&
            (w_is_int(recv) || w_is_double(recv) || w_is_numeric_tag(recv) || w_is_domain_obj(recv)))
            return w_mul(recv, args->slots[0]);
    }

    /* Universal respond_to? — reflective method-existence check. Declared
     * bodyless in core/object.w so the runtime supplies it (the hypercomplex
     * tower's scalar_like? relies on it: `!@1.respond_to?("components")`).
     * Instances consult their class's instance methods (walking inheritance);
     * classes consult static methods; builtin-typed receivers answer false. */
    if (w_hash_key_eq(name, WN_respond_to_q) && args->size >= 1) {
        WValue mname = args->slots[0];
        if (w_is_instance(recv))
            return w_bool(w_method_lookup(g_class_table[((WObject *)w_as_ptr(recv))->class_id], mname) != NULL);
        if (w_is_class(recv))
            return w_bool(w_static_method_lookup((WClass *)w_as_ptr(recv), mname) != NULL);
        return w_bool(0);
    }

    /* Universal spaceship: a <=> b → -1/0/1 (nil if incomparable). Backs
     * Comparable for the builtin ordered types (Integer/BigInt/Float/
     * Decimal/Char/Instant/String). User instances that define their own
     * <=> are dispatched by the normal method lookup below, before this is
     * reached — this only rescues builtin receivers that would otherwise
     * hit "undefined method '<=>'". */
    if (w_hash_key_eq(name, WN_spaceship) && args->size >= 1
        && !w_is_instance(recv) && !w_is_class(recv)) {
        return w_spaceship(recv, args->slots[0]);
    }

    /* Universal is_a?(class) — instance ancestry walk (an instance is_a? its
     * class and every superclass); primitives compare by builtin type name.
     * Backs the synthesized operator-overload dispatcher and is useful on its
     * own. A non-class argument or unrelated receiver answers false. */
    if (w_hash_key_eq(name, WN_is_a_q) && args->size >= 1) {
        return w_value_is_a(recv, args->slots[0]);
    }

    const char *type_name =
        w_is_int(recv) ? "Integer" :
        w_is_double(recv) ? "Float" :
        w_is_string(recv) ? "String" :
        w_is_symbol(recv) ? "Symbol" :
        w_is_array(recv) ? "Array" :
        w_is_bool(recv) ? "Boolean" :
        w_is_nil(recv) ? "nil" :
        w_is_channel(recv) ? "Channel" :
        w_is_socket(recv) ? "Socket" :
        w_is_bytes(recv) ? "ByteArray" :
        w_is_strbuf(recv) ? "StringBuffer" :
        w_is_instance(recv) ? g_class_table[((WObject *)w_as_ptr(recv))->class_id]->name :
        w_is_class(recv) ? ((WClass *)w_as_ptr(recv))->name : "Object";
    dief("undefined method '%s' for %s (%s 0x%llx)",
         as_str(name), type_name, w_type_label(recv), (unsigned long long)recv);
    return W_NIL;
}

/* ---- Memoization (open-addressing hash table) ---- */

#define MEMO_MAGIC "WMEM"

/* FNV-1a hash over raw WValue key bytes */
static uint64_t memo_hash(WValue *args, int arity) {
    uint64_t h = 14695981039346656037ULL;
    const uint8_t *p = (const uint8_t *)args;
    int nbytes = arity * (int)sizeof(WValue);
    for (int i = 0; i < nbytes; i++) {
        h ^= p[i];
        h *= 1099511628211ULL;
    }
    return h;
}

static void memo_alloc(WMemoTable *t, int cap) {
    t->cap = cap;
    int arity = t->arity > 0 ? t->arity : 1;
    t->keys = malloc(sizeof(WValue) * cap * arity);
    for (int i = 0; i < cap; i++) t->keys[i * arity] = W_UNDEF;
    t->values = calloc(1, sizeof(WValue) * cap);
}

static void memo_insert_raw(WMemoTable *t, WValue *key, WValue val) {
    uint64_t h = memo_hash(key, t->arity);
    int mask = t->cap - 1;
    int idx = (int)(h & (uint64_t)mask);
    int arity = t->arity;
    while (t->keys[idx * arity] != W_UNDEF) {
        idx = (idx + 1) & mask;
    }
    memcpy(&t->keys[idx * arity], key, arity * sizeof(WValue));
    t->values[idx] = val;
    t->count++;
}

static void memo_resize(WMemoTable *t) {
    int old_cap = t->cap;
    WValue *old_keys = t->keys;
    WValue *old_values = t->values;
    int old_arity = t->arity;

    t->count = 0;
    memo_alloc(t, old_cap * 2);

    for (int i = 0; i < old_cap; i++) {
        if (old_keys[i * old_arity] != W_UNDEF) {
            memo_insert_raw(t, &old_keys[i * old_arity], old_values[i]);
        }
    }
}

static void w_memo_load(WMemoTable *t, const char *sha) {
    const char *home = getenv("HOME");
    if (!home) return;

    char path[512];
    snprintf(path, sizeof(path), "%s/.tungsten/cache/%s.memo", home, sha);

    FILE *f = fopen(path, "rb");
    if (!f) return;

    /* Read and verify header */
    char magic[4];
    uint32_t version, file_arity, file_count;
    if (fread(magic, 1, 4, f) != 4 || memcmp(magic, MEMO_MAGIC, 4) != 0) { fclose(f); return; }
    if (fread(&version, 4, 1, f) != 1 || version != MEMO_VERSION) { fclose(f); return; }
    if (fread(&file_arity, 4, 1, f) != 1) { fclose(f); return; }
    if (fread(&file_count, 4, 1, f) != 1) { fclose(f); return; }

    if ((int)file_arity != t->arity && t->arity != 0) { fclose(f); return; }
    t->arity = (int)file_arity;

    int needed = (int)file_count;
    if (needed > MEMO_MAX_ENTRIES) needed = MEMO_MAX_ENTRIES;

    int cap = 256;
    while (cap * MEMO_HT_LOAD_NUM < needed * MEMO_HT_LOAD_DEN * 2) cap *= 2;
    memo_alloc(t, cap);

    WValue *entry_buf = calloc(1, sizeof(WValue) * t->arity);
    for (int i = 0; i < needed; i++) {
        if (fread(entry_buf, sizeof(WValue), t->arity, f) != (size_t)t->arity) { fclose(f); return; }
        WValue val;
        if (fread(&val, sizeof(WValue), 1, f) != 1) { fclose(f); return; }
        memo_insert_raw(t, entry_buf, val);
    }
    fclose(f);
}

void *w_memo_init(const char *sha) {
    WMemoTable *t = calloc(1, sizeof(WMemoTable));
    t->arity = 0;
    t->count = 0;
    t->cap = 0;
    t->keys = NULL;
    t->values = NULL;
    memset(t->sha, 0, 17);
    if (sha) {
        strncpy(t->sha, sha, 16);
        t->sha[16] = '\0';
        w_memo_load(t, sha);
    }

    return t;
}

WValue w_memo_lookup(void *table, WValue *args, int arity) {
    WMemoTable *t = (WMemoTable *)table;
    if (t->arity == 0 && arity != 0) t->arity = arity;
    if (!t->keys) memo_alloc(t, 256);

    uint64_t h = memo_hash(args, arity);
    int mask = t->cap - 1;
    int idx = (int)(h & (uint64_t)mask);
    int a = t->arity > 0 ? t->arity : 1;

    while (t->keys[idx * a] != W_UNDEF) {
        WValue *k = &t->keys[idx * a];
        int match = 1;
        for (int j = 0; j < arity; j++) {
            if (k[j] != args[j]) { match = 0; break; }
        }
        if (match) return t->values[idx];
        idx = (idx + 1) & mask;
    }

    return W_MEMO_MISS;
}

void w_memo_store(void *table, WValue *args, int arity, WValue result) {
    WMemoTable *t = (WMemoTable *)table;
    if (t->arity == 0 && arity != 0) t->arity = arity;
    if (!t->keys) memo_alloc(t, 256);

    if (t->count >= MEMO_MAX_ENTRIES) return;

    if ((t->count + 1) * MEMO_HT_LOAD_DEN > t->cap * MEMO_HT_LOAD_NUM) {
        memo_resize(t);
    }

    memo_insert_raw(t, args, result);
}

void w_memo_save(void *table, const char *sha) {
    WMemoTable *t = (WMemoTable *)table;
    if (t->count == 0) return;

    const char *home = getenv("HOME");
    if (!home) return;

    char dir[512];
    snprintf(dir, sizeof(dir), "%s/.tungsten", home);
    mkdir(dir, 0755);
    snprintf(dir, sizeof(dir), "%s/.tungsten/cache", home);
    mkdir(dir, 0755);

    char path[512];
    snprintf(path, sizeof(path), "%s/.tungsten/cache/%s.memo", home, sha);

    FILE *f = fopen(path, "wb");
    if (!f) return;

    fwrite(MEMO_MAGIC, 1, 4, f);
    uint32_t version = MEMO_VERSION;
    uint32_t w_arity = (uint32_t)t->arity;
    uint32_t w_count = (uint32_t)t->count;
    fwrite(&version, 4, 1, f);
    fwrite(&w_arity, 4, 1, f);
    fwrite(&w_count, 4, 1, f);

    int a = t->arity > 0 ? t->arity : 1;
    for (int i = 0; i < t->cap; i++) {
        if (t->keys[i * a] != W_UNDEF) {
            fwrite(&t->keys[i * a], sizeof(WValue), t->arity, f);
            fwrite(&t->values[i], sizeof(WValue), 1, f);
        }
    }
    fclose(f);
}

/* ---- Memoized call wrappers ---- */

WValue __w_memo_call0_i64(void *table, WValue (*fn)(void)) {
    WValue args[1] = {0};
    WValue cached = w_memo_lookup(table, args, 0);
    if (cached != W_MEMO_MISS) return cached;
    WValue result = fn();
    w_memo_store(table, args, 0, result);
    return result;
}

WValue __w_memo_call1_i64(void *table, WValue (*fn)(WValue), WValue arg0) {
    WValue args[1] = {arg0};
    WValue cached = w_memo_lookup(table, args, 1);
    if (cached != W_MEMO_MISS) return cached;
    WValue result = fn(arg0);
    w_memo_store(table, args, 1, result);
    return result;
}

WValue __w_memo_call2_i64(void *table, WValue (*fn)(WValue, WValue), WValue arg0, WValue arg1) {
    WValue args[2] = {arg0, arg1};
    WValue cached = w_memo_lookup(table, args, 2);
    if (cached != W_MEMO_MISS) return cached;
    WValue result = fn(arg0, arg1);
    w_memo_store(table, args, 2, result);
    return result;
}

/* GC mark procedure removed — no longer using Boehm GC */
void w_gc_mark_roots(void) { /* no-op */ }

/* ---- Value inspector ---- */

WValue w_inspect_s(WValue v) {
    char buf[128];
    if (w_is_nil(v)) {
        snprintf(buf, sizeof(buf), "[0x%016llX] nil", (unsigned long long)v);
    } else if (w_is_false(v)) {
        snprintf(buf, sizeof(buf), "[0x%016llX] false", (unsigned long long)v);
    } else if (w_is_true(v)) {
        snprintf(buf, sizeof(buf), "[0x%016llX] true", (unsigned long long)v);
    } else if (w_is_int(v)) {
        snprintf(buf, sizeof(buf), "[0x%016llX] int(%lld)",
                 (unsigned long long)v, (long long)w_as_int(v));
    } else if (w_is_double(v)) {
        snprintf(buf, sizeof(buf), "[0x%016llX] double(%g)",
                 (unsigned long long)v, w_as_double(v));
    } else if (w_is_decimal(v)) {
        snprintf(buf, sizeof(buf), "[0x%016llX] decimal(sig=%lld, scale=%d)",
                 (unsigned long long)v,
                 (long long)((int64_t)((v >> 7) & 0x1FFFFFFFFFFULL) << 23 >> 23),
                 (int)((int8_t)((v & 0x7F) << 1) >> 1));
    } else if (w_is_char(v)) {
        uint32_t cp = w_char_codepoint(v);
        snprintf(buf, sizeof(buf), "[0x%016llX] char(U+%04X)",
                 (unsigned long long)v, cp);
    } else if (w_is_symbol(v)) {
        char sbuf[6];
        const char *s;
        size_t len;
        w_str_data(v, sbuf, &s, &len);
        snprintf(buf, sizeof(buf), "[0x%016llX] symbol(:%.*s)",
                 (unsigned long long)v,
                 (int)len, s);
    } else if (w_is_instant(v)) {
        snprintf(buf, sizeof(buf), "[0x%016llX] instant(%lld ms)",
                 (unsigned long long)v, (long long)w_unbox_instant(v));
    } else if (w_is_string(v)) {
        const char *s = as_str(v);
        snprintf(buf, sizeof(buf), "[0x%016llX] string(\"%.*s\")",
                 (unsigned long long)v, 40, s);
    } else if (w_is_obj(v)) {
        void *ptr = w_as_ptr(v);
        const char *kind = "generic";
        switch (w_subtag(v)) {
            case W_SUBTAG_ARRAY:   kind = "array";   break;
            case W_SUBTAG_HASH:    kind = "hash";    break;
            case W_SUBTAG_CLOSURE: kind = "closure"; break;
            case W_SUBTAG_INSTANCE:  kind = "instance";  break;
            case W_SUBTAG_CLASS:   kind = "class";   break;
        }
        snprintf(buf, sizeof(buf), "[0x%016llX] object(%s, ptr=%p)",
                 (unsigned long long)v, kind, ptr);
    } else {
        snprintf(buf, sizeof(buf), "[0x%016llX] unknown", (unsigned long long)v);
    }
    return w_string(buf);
}

void w_inspect(WValue v) {
    WValue s = w_inspect_s(v);
    fprintf(stderr, "%s\n", as_str(s));
}

